  1	import * as React from 'react';
  2	import { getName, getUID } from '@odf/shared/selectors';
  3	import {
  4	  TopologySearchContext,
  5	  TopologyDataContext,
  6	  TopologyViewLevel,
  7	} from '@odf/shared/topology';
  8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  9	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk-internal/lib/extensions/console-types';
 10	import * as fuzzy from 'fuzzysearch';
 11	import { SearchInput } from '@patternfly/react-core';
 12	import { useVisualizationController } from '@patternfly/react-topology';
 13	import { STEP_INTO_EVENT, STEP_TO_CLUSTER } from '../constants';
 14	
 15	const useTopologySearch = () => {
 16	  const { visualizationLevel, nodes, deployments } =
 17	    React.useContext(TopologyDataContext);
 18	
 19	  const { activeItemsUID, setActiveItemsUID } = React.useContext(
 20	    TopologySearchContext
 21	  );
 22	
 23	  const controller = useVisualizationController();
 24	
 25	  const performSearch = React.useCallback(
 26	    (input) => {
 27	      let resourcesInScope: K8sResourceCommon[] = nodes;
 28	      if (visualizationLevel === TopologyViewLevel.DEPLOYMENTS) {
 29	        const visibleElements = controller.getElements();
 30	        const visibleIDs = visibleElements.map((element) => element.getId());
 31	        const filteredDeployments = deployments.filter((deployment) =>
 32	          visibleIDs.includes(deployment.metadata.uid)
 33	        );
 34	        resourcesInScope = filteredDeployments;
 35	      }
 36	      // Process the search now
 37	      const filteredItems = resourcesInScope
 38	        .filter((item) => {
 39	          const itemName = getName(item);
 40	          if (fuzzy(input, itemName)) {
 41	            return true;
 42	          }
 43	          return false;
 44	        })
 45	        .map(getUID);
 46	      setActiveItemsUID(filteredItems);
 47	      return filteredItems;
 48	    },
 49	    [nodes, visualizationLevel, setActiveItemsUID, controller, deployments]
 50	  );
 51	
 52	  return { performSearch, activeItemsUID };
 53	};
 54	
 55	const SearchBar: React.FC = () => {
 56	  const [userInput, setUserInput] = React.useState('');
 57	  const [currentResult, setCurrentResult] = React.useState(0);
 58	  const controller = useVisualizationController();
 59	
 60	  const { performSearch, activeItemsUID } = useTopologySearch();
 61	
 62	  const { setActiveItemsUID, setActiveItem } = React.useContext(
 63	    TopologySearchContext
 64	  );
 65	
 66	  const resultsCount = activeItemsUID.length;
 67	
 68	  const { t } = useCustomTranslation();
 69	
 70	  const onChange = (_event, input: string) => {
 71	    setUserInput(input);
 72	  };
 73	
 74	  const onClear = React.useCallback(() => {
 75	    setUserInput('');
 76	    setCurrentResult(0);
 77	    setActiveItemsUID([]);
 78	    setActiveItem('');
 79	  }, [setActiveItem, setActiveItemsUID]);
 80	
 81	  const onSearch = () => {
 82	    const items = performSearch(userInput);
 83	    setActiveItem(items[0]);
 84	  };
 85	
 86	  const onNext = () => {
 87	    const newCurrentResult = currentResult + 1;
 88	    setCurrentResult(
 89	      newCurrentResult > resultsCount ? resultsCount : newCurrentResult
 90	    );
 91	    setActiveItem(activeItemsUID[newCurrentResult]);
 92	  };
 93	
 94	  const onPrevious = () => {
 95	    const newCurrentResult = currentResult - 1;
 96	    setCurrentResult(newCurrentResult >= 0 ? newCurrentResult : 1);
 97	    setActiveItem(activeItemsUID[newCurrentResult]);
 98	  };
 99	
100	  React.useEffect(() => {
101	    controller.addEventListener(STEP_INTO_EVENT, onClear);
102	    controller.addEventListener(STEP_TO_CLUSTER, onClear);
103	    return () => {
104	      controller.removeEventListener(STEP_INTO_EVENT, onClear);
105	      controller.removeEventListener(STEP_TO_CLUSTER, onClear);
106	    };
107	  }, [controller, onClear]);
108	
109	  return (
110	    <SearchInput
111	      isNextNavigationButtonDisabled={resultsCount === currentResult + 1}
112	      isPreviousNavigationButtonDisabled={currentResult === 0}
113	      value={userInput}
114	      placeholder={t('Search...')}
115	      onNextClick={onNext}
116	      onPreviousClick={onPrevious}
117	      onClear={onClear}
118	      onChange={onChange as any} // Todo(bipuladh): Types are wrong so using any. Fix types
119	      onSearch={onSearch}
120	      resultsCount={
121	        resultsCount > 0 ? `${currentResult + 1} of ${resultsCount}` : undefined
122	      }
123	    />
124	  );
125	};
126	
127	export default SearchBar;

